<script setup lang="ts">
const props = defineProps({
  size: {
    type: String,
    default: "24",
  },
  class: {
    type: String,
    default: "stroke-gray-900",
  },
  defaultIcon: {
    type: String,
    default: "Alert",
  },
});

const getIcons = () => {
  const iconContext = import.meta.glob("../../icons/*/index.vue", { eager: true });
  
  return Object.entries(iconContext).reduce((acc, [path, module]) => {

    const match = path.match(/\/icons\/([^/]+)\/index\.vue$/);
    if (match) {
      const name = match[1];
      acc[name] = (module as any).default;
    }
    return acc;
  }, {} as Record<string, any>);
};

const iconComponents = getIcons();
const allIcons = Object.keys(iconComponents);

const tableColumnsCount = 4;
const tableRowsCount = Math.ceil(allIcons.length / tableColumnsCount);

const groupedIcons: any = [];
let tempArray = [...allIcons];


for (let i = 0; i < tableRowsCount; i++) {
  const icons = tempArray.splice(0, tableColumnsCount);
  
  groupedIcons.push(icons);
}

const selectedIcon = ref(props.defaultIcon);

const selectIcon = (iconName: string) => {
  selectedIcon.value = iconName;
};
</script>

<template>
  <div class="container mx-auto p-4">
    <div class="mb-6 p-4">
      <div class="flex justify-center items-center gap-4">
        <component
          v-if="selectedIcon"
          :is="iconComponents[selectedIcon]"
          :size="props.size"
          :class="props.class"
        />
        <div>
          <p class="text-sm font-medium">{{ selectedIcon }}</p>
          <p class="text-xs text-gray-500">
            <code>npx transtrack-ui add {{ selectedIcon }}</code>
          </p>
        </div>
      </div>
    </div>

    <table class="table-auto w-full border-collapse">
      <tbody>
        <tr v-for="(row, rowIndex) in groupedIcons" :key="`row-${rowIndex}`">
          <template
            v-for="(iconName, colIndex) in row"
            :key="`icon-${rowIndex}-${colIndex}`"
          >
            <td class="p-2 border border-gray-300 text-center">
              <div
                class="flex justify-center items-center p-2 cursor-pointer hover:bg-primary-100 rounded-md"
                :class="{ 'bg-primary-100': iconName === selectedIcon }"
                @click="selectIcon(iconName)"
              >
                <component
                  :is="iconComponents[iconName]"
                  :size="props.size"
                  :class="props.class"
                />
              </div>
            </td>
            <td class="p-2 border border-gray-300">
              <span class="text-sm">{{ iconName }}</span>
            </td>
          </template>
        </tr>
      </tbody>
    </table>
  </div>
</template>
